const ALL_TASKS = [
  { id: 1, title: 'Review product roadmap', priority: 'high', done: false, category: 'Work', eta: '2h' },
  { id: 2, title: 'Write weekly report', priority: 'medium', done: true, category: 'Work', eta: '1h' },
  { id: 3, title: 'Update design system', priority: 'high', done: false, category: 'Design', eta: '3h' },
  { id: 4, title: 'Team standup prep', priority: 'low', done: false, category: 'Work', eta: '15m' },
  { id: 5, title: 'Read UX research doc', priority: 'medium', done: false, category: 'Research', eta: '1.5h' },
];

function StatsHeader({ tasks }) {
  const done = tasks.filter(t => t.done).length;
  const total = tasks.length;
  const pct = total > 0 ? Math.round((done / total) * 100) : 0;
  return (
    <div data-dg-component="statsHeader" className="bg-white px-5 pt-4 pb-4 border-b border-slate-100">
      <div className="flex justify-between items-center mb-3">
        <div>
          <div className="text-[22px] font-extrabold text-slate-900">Today</div>
          <div className="text-[13px] text-slate-400">Monday, March 24</div>
        </div>
        <div className="text-right">
          <div className="text-[28px] font-extrabold text-slate-900">{pct}%</div>
          <div className="text-[12px] text-slate-400">{done}/{total} done</div>
        </div>
      </div>
      <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
        <div className="h-full bg-gradient-to-r from-violet-500 to-indigo-500 rounded-full transition-[width] duration-500" style={{ width: `${pct}%` }} />
      </div>
    </div>
  );
}

function SearchBar({ query, onChange }) {
  return (
    <div data-dg-component="searchBar" className="mx-4 mt-3">
      <div className="flex items-center bg-slate-100 rounded-xl px-3 py-2.5 gap-2">
        <span className="text-slate-400 text-sm">🔍</span>
        <input value={query} onChange={e => onChange(e.target.value)}
          placeholder="Search tasks..."
          className="flex-1 bg-transparent border-0 outline-none text-sm text-slate-700 placeholder:text-slate-400" />
        {query && <button onClick={() => onChange('')} className="text-slate-400 text-sm border-0 bg-transparent cursor-pointer">×</button>}
      </div>
    </div>
  );
}

function FilterTabs({ filter, onSelect }) {
  return (
    <div data-dg-component="filterTabs" className="flex gap-1.5 px-4 mt-3 overflow-x-auto pb-1" style={{ scrollbarWidth: 'none' }}>
      {['all', 'high', 'medium', 'low'].map(f => (
        <button key={f} onClick={() => onSelect(f)}
          className={`shrink-0 rounded-full px-3 py-1 text-xs font-semibold border-0 cursor-pointer ${filter === f ? 'bg-violet-500 text-white' : 'bg-slate-100 text-slate-500'}`}>
          {f === 'all' ? 'All' : f.charAt(0).toUpperCase() + f.slice(1)}
        </button>
      ))}
    </div>
  );
}

function TaskList({ tasks, onToggle }) {
  const priorityDot = { high: 'bg-red-400', medium: 'bg-amber-400', low: 'bg-emerald-400' };
  return (
    <div data-dg-component="taskList" className="px-4 pt-3 pb-8">
      {tasks.length === 0 && (
        <div className="text-center py-10 text-slate-400">
          <div className="text-3xl mb-2">✅</div>
          <div className="text-sm font-semibold">No tasks found</div>
        </div>
      )}
      {tasks.map(task => (
        <div key={task.id} onClick={() => onToggle(task.id)}
          className={`bg-white rounded-2xl p-4 mb-2.5 shadow-sm cursor-pointer flex items-start gap-3 ${task.done ? 'opacity-60' : ''}`}>
          <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center mt-0.5 shrink-0 ${task.done ? 'bg-violet-500 border-violet-500' : 'border-slate-300'}`}>
            {task.done && <span className="text-white text-[10px]">✓</span>}
          </div>
          <div className="flex-1 min-w-0">
            <div className={`text-[14px] font-semibold text-slate-900 ${task.done ? 'line-through text-slate-400' : ''}`}>{task.title}</div>
            <div className="flex items-center gap-2 mt-1">
              <div className={`w-1.5 h-1.5 rounded-full ${priorityDot[task.priority]}`} />
              <span className="text-xs text-slate-400">{task.category}</span>
              <span className="text-xs text-slate-400">· {task.eta}</span>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

function App() {
  const [tasks, setTasks] = React.useState(ALL_TASKS);
  const [query, setQuery] = React.useState('');
  const [filter, setFilter] = React.useState('all');

  const filtered = tasks.filter(t => {
    const matchQ = t.title.toLowerCase().includes(query.toLowerCase());
    const matchF = filter === 'all' || t.priority === filter;
    return matchQ && matchF;
  });

  const toggle = (id) => setTasks(prev => prev.map(t => t.id === id ? { ...t, done: !t.done } : t));

  return (
    <div className="min-h-screen bg-slate-50 font-sans max-w-[390px] mx-auto">
      <StatsHeader tasks={tasks} />
      <SearchBar query={query} onChange={setQuery} />
      <FilterTabs filter={filter} onSelect={setFilter} />
      <TaskList tasks={filtered} onToggle={toggle} />
    </div>
  );
}

function SessionHeader({ task, onChangeTask }) {
  const tasks = ['Review product roadmap', 'Update design system', 'Read UX research doc'];
  return (
    <div data-dg-component="sessionHeader" className="bg-white px-5 pt-4 pb-4 border-b border-slate-100">
      <div className="text-[11px] text-slate-400 tracking-widest uppercase mb-1">Focusing on</div>
      <div className="text-[16px] font-bold text-slate-900 mb-3 truncate">{task}</div>
      <div className="flex gap-2 overflow-x-auto" style={{ scrollbarWidth: 'none' }}>
        {tasks.map(t => (
          <button key={t} onClick={() => onChangeTask(t)}
            className={`shrink-0 text-xs font-semibold px-3 py-1.5 rounded-full border-0 cursor-pointer ${t === task ? 'bg-violet-500 text-white' : 'bg-slate-100 text-slate-500'}`}>
            {t.length > 22 ? t.slice(0, 22) + '…' : t}
          </button>
        ))}
      </div>
    </div>
  );
}

function TimerRing({ seconds, isRunning, onStart, onPause }) {
  const total = 25 * 60;
  const pct = (seconds / total) * 100;
  const mm = String(Math.floor(seconds / 60)).padStart(2, '0');
  const ss = String(seconds % 60).padStart(2, '0');
  const r = 80;
  const circ = 2 * Math.PI * r;
  const offset = circ * (1 - pct / 100);
  return (
    <div data-dg-component="timerRing" className="flex flex-col items-center py-8 bg-white mx-4 mt-4 rounded-[24px] shadow-sm">
      <div className="relative w-[200px] h-[200px] flex items-center justify-center">
        <svg className="absolute top-0 left-0 -rotate-90" width="200" height="200">
          <circle cx="100" cy="100" r={r} fill="none" stroke="#f1f5f9" strokeWidth="12" />
          <circle cx="100" cy="100" r={r} fill="none" stroke="#8b5cf6" strokeWidth="12"
            strokeDasharray={circ} strokeDashoffset={offset} strokeLinecap="round"
            style={{ transition: 'stroke-dashoffset 1s linear' }} />
        </svg>
        <div className="text-center z-10">
          <div className="text-[42px] font-extrabold text-slate-900 tracking-tight">{mm}:{ss}</div>
          <div className="text-[13px] text-slate-400 mt-0.5">Focus Session</div>
        </div>
      </div>
      <div className="flex gap-3 mt-6">
        <button onClick={isRunning ? onPause : onStart}
          className={`px-8 py-3 rounded-full border-0 cursor-pointer text-[15px] font-bold ${isRunning ? 'bg-slate-200 text-slate-700' : 'bg-violet-500 text-white shadow-lg'}`}>
          {isRunning ? '⏸ Pause' : '▶ Start'}
        </button>
      </div>
    </div>
  );
}

function SessionStats({ sessions, totalFocusMin }) {
  return (
    <div data-dg-component="sessionStats" className="mx-4 mt-3 grid grid-cols-3 gap-2">
      {[
        { label: 'Sessions', value: sessions, emoji: '🎯' },
        { label: 'Focus Time', value: `${totalFocusMin}m`, emoji: '⏱' },
        { label: 'Streak', value: '3 days', emoji: '🔥' },
      ].map(s => (
        <div key={s.label} className="bg-white rounded-[18px] p-3 shadow-sm text-center">
          <div className="text-[20px]">{s.emoji}</div>
          <div className="text-[15px] font-bold text-slate-900 mt-1">{s.value}</div>
          <div className="text-[10px] text-slate-400">{s.label}</div>
        </div>
      ))}
    </div>
  );
}

function DistractionTracker({ count, onLog }) {
  return (
    <div data-dg-component="distractionTracker" className="mx-4 mt-3 bg-white rounded-[20px] p-4 shadow-sm">
      <div className="flex items-center justify-between mb-2">
        <div>
          <div className="text-[14px] font-bold text-slate-900">Distractions</div>
          <div className="text-[12px] text-slate-400">{count} logged today</div>
        </div>
        <button onClick={onLog}
          className="bg-amber-50 text-amber-600 border-0 rounded-full px-4 py-2 text-[12px] font-semibold cursor-pointer">
          + Log One
        </button>
      </div>
      <div className="flex gap-1 flex-wrap">
        {Array.from({ length: count }).map((_, i) => (
          <div key={i} className="w-3 h-3 rounded-full bg-amber-400" />
        ))}
        {count === 0 && <div className="text-[12px] text-slate-400">No distractions — great focus! 🎉</div>}
      </div>
    </div>
  );
}

function App() {
  const [task, setTask] = React.useState('Review product roadmap');
  const [seconds, setSeconds] = React.useState(25 * 60);
  const [isRunning, setIsRunning] = React.useState(false);
  const [sessions, setSessions] = React.useState(2);
  const [totalFocusMin, setTotalFocusMin] = React.useState(47);
  const [distractions, setDistractions] = React.useState(3);

  React.useEffect(() => {
    if (!isRunning) return;
    const id = setInterval(() => {
      setSeconds(s => {
        if (s <= 1) { setIsRunning(false); setSessions(n => n + 1); setTotalFocusMin(m => m + 25); return 25 * 60; }
        return s - 1;
      });
    }, 1000);
    return () => clearInterval(id);
  }, [isRunning]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans max-w-[390px] mx-auto pb-8">
      <SessionHeader task={task} onChangeTask={setTask} />
      <TimerRing seconds={seconds} isRunning={isRunning} onStart={() => setIsRunning(true)} onPause={() => setIsRunning(false)} />
      <SessionStats sessions={sessions} totalFocusMin={totalFocusMin} />
      <DistractionTracker count={distractions} onLog={() => setDistractions(d => d + 1)} />
    </div>
  );
}
